import pika
import subprocess
import json
import logging
import os
import shlex

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# SECURITY: Only these commands are allowed to be executed.
# Map of task_name -> (executable_path, allowed_args_pattern)
ALLOWED_COMMANDS = {
    "generate_report": {
        "executable": "/usr/local/bin/generate_report.sh",
        "allowed_args": ["--date", "--output-dir", "--format"],
        "max_args": 6,
    },
    "compress_files": {
        "executable": "/usr/local/bin/compress_files.sh",
        "allowed_args": ["--input-dir", "--output-file"],
        "max_args": 4,
    },
    "data_export": {
        "executable": "/usr/local/bin/data_export.sh",
        "allowed_args": ["--table", "--format", "--destination"],
        "max_args": 6,
    },
}

# Characters that are never allowed in arguments (prevent shell injection)
FORBIDDEN_CHARS = set(";|&`$(){}[]!#~<>\\'\"\n\r")


def validate_argument(value: str) -> bool:
    """Validate that an argument value doesn't contain shell injection characters."""
    if not isinstance(value, str):
        return False
    if len(value) > 256:
        return False
    if any(c in FORBIDDEN_CHARS for c in value):
        return False
    return True


def build_safe_command(task_name: str, args: dict) -> list:
    """
    Build a safe command list from a task name and arguments.
    Returns a list suitable for subprocess.run with shell=False.
    """
    if task_name not in ALLOWED_COMMANDS:
        raise ValueError(f"Unknown task: {task_name}")

    task_config = ALLOWED_COMMANDS[task_name]
    executable = task_config["executable"]

    if not os.path.isfile(executable):
        raise FileNotFoundError(f"Executable not found: {executable}")

    cmd = [executable]

    if len(args) * 2 > task_config["max_args"]:
        raise ValueError(f"Too many arguments for task {task_name}")

    for key, value in args.items():
        if key not in task_config["allowed_args"]:
            raise ValueError(f"Argument '{key}' not allowed for task '{task_name}'")

        if not validate_argument(value):
            raise ValueError(f"Invalid characters in argument value for '{key}'")

        cmd.append(key)
        cmd.append(value)

    return cmd


def process_message(ch, method, properties, body):
    """Process a job message from the queue."""
    try:
        message = json.loads(body.decode("utf-8"))

        task_name = message.get("task")
        task_args = message.get("args", {})
        job_id = message.get("job_id", "unknown")

        if not task_name:
            logger.error(f"Job {job_id}: No task name provided")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            return

        logger.info(f"Job {job_id}: Processing task '{task_name}'")

        # Build a safe command — no arbitrary shell commands allowed
        safe_command = build_safe_command(task_name, task_args)

        logger.info(f"Job {job_id}: Executing {safe_command}")

        # SECURITY: shell=False prevents shell injection
        # timeout prevents runaway processes
        result = subprocess.run(
            safe_command,
            shell=False,  # NEVER use shell=True with external input
            capture_output=True,
            text=True,
            timeout=300,  # 5 minute timeout
            cwd="/tmp",  # Restrict working directory
            env={  # Minimal environment
                "PATH": "/usr/local/bin:/usr/bin:/bin",
                "HOME": "/tmp",
                "LANG": "C.UTF-8",
            },
        )

        if result.returncode == 0:
            logger.info(f"Job {job_id}: Completed successfully")
            logger.debug(f"Job {job_id}: stdout: {result.stdout[:500]}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        else:
            logger.error(
                f"Job {job_id}: Failed with return code {result.returncode}"
            )
            logger.error(f"Job {job_id}: stderr: {result.stderr[:500]}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    except json.JSONDecodeError:
        logger.error("Failed to decode message as JSON")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except (ValueError, FileNotFoundError) as e:
        logger.error(f"Validation error: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except subprocess.TimeoutExpired:
        logger.error(f"Job {job_id}: Timed out after 300 seconds")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    except Exception as e:
        logger.error(f"Unexpected error: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)


def main():
    """Main consumer loop."""
    rabbitmq_host = os.environ.get("RABBITMQ_HOST", "localhost")
    rabbitmq_port = int(os.environ.get("RABBITMQ_PORT", 5672))
    rabbitmq_user = os.environ.get("RABBITMQ_USER", "guest")
    rabbitmq_pass = os.environ.get("RABBITMQ_PASS", "guest")
    queue_name = os.environ.get("JOB_QUEUE", "batch_jobs")

    credentials = pika.PlainCredentials(rabbitmq_user, rabbitmq_pass)
    parameters = pika.ConnectionParameters(
        host=rabbitmq_host,
        port=rabbitmq_port,
        credentials=credentials,
        heartbeat=600,
    )

    connection = pika.BlockingConnection(parameters)
    channel = connection.channel()

    channel.queue_declare(queue=queue_name, durable=True)
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=queue_name, on_message_callback=process_message)

    logger.info(f"Waiting for jobs on queue '{queue_name}'. Press CTRL+C to exit.")

    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        logger.info("Shutting down...")
        channel.stop_consuming()
    finally:
        connection.close()


if __name__ == "__main__":
    main()

